+/**
+ * Check whether a notification type is enabled for a given channel's preferences.
+ * Works with any channel preferences that have an enabled toggle and categories.
+ */
+export function isChannelNotificationEnabled(
+  preferences: { enabled: boolean; categories: ChannelCategoryPreferences },
+  notificationType: NotificationType,
+): boolean {
+  if (!preferences.enabled) {
+    return false;
+  }
+  return preferences.categories[notificationType] ?? false;
+}
+
+/**
+ * Get the effective channel preferences for a user, falling back to defaults
+ * for channels not explicitly configured.
+ */
+export function getChannelPreferences(
+  prefs: UserNotificationPreferences,
+  channel: NotificationChannel,
+): { enabled: boolean; categories: ChannelCategoryPreferences } {
+  switch (channel) {
+    case 'email':
+      return prefs.email;
+    case 'sms':
+      return prefs.sms ?? DEFAULT_SMS_PREFERENCES;
+    case 'webhook':
+      return prefs.webhook ?? DEFAULT_WEBHOOK_PREFERENCES;
+    default:
+      // For unknown channels (e.g. 'in-app'), default to all-enabled
+      return { enabled: true, categories: { ...DEFAULT_CATEGORIES } };
+  }
+}

