parameters.new_string:
/**
 * User notification preferences model.
 *
 * Controls how and when notifications are delivered to users.
 * Supports per-channel settings for email, SMS, and webhook channels.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

/**
 * How often email notifications are delivered.
 * - 'immediate': Send as events occur
 * - 'daily-digest': Batch into a daily summary
 * - 'weekly-digest': Batch into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * Per-category subscription settings for notifications.
 * Keys map to NotificationType values.
 */
export interface ChannelCategoryPreferences {
  'order-confirmation': boolean;
  'order-status-update': boolean;
  'welcome': boolean;
  'user-updated': boolean;
}

/** @deprecated Use ChannelCategoryPreferences instead */
export type EmailCategoryPreferences = ChannelCategoryPreferences;

/**
 * Email-specific notification preferences.
 */
export interface EmailNotificationPreferences {
  /** Whether email notifications are enabled at all */
  enabled: boolean;
  /** Delivery frequency */
  frequency: EmailFrequency;
  /** Per-category opt-in/out */
  categories: ChannelCategoryPreferences;
}

/**
 * SMS-specific notification preferences.
 */
export interface SmsNotificationPreferences {
  /** Whether SMS notifications are enabled at all */
  enabled: boolean;
  /** Per-category opt-in/out */
  categories: ChannelCategoryPreferences;
}

/**
 * Webhook-specific notification preferences.
 */
export interface WebhookNotificationPreferences {
  /** Whether webhook notifications are enabled at all */
  enabled: boolean;
  /** Per-category opt-in/out */
  categories: ChannelCategoryPreferences;
}

/**
 * Full user notification preferences record.
 * SMS and webhook fields are optional for backward compatibility with
 * existing email-only records. Missing channel defaults to all-enabled.
 */
export interface UserNotificationPreferences {
  id: string;
  userId: string;
  email: EmailNotificationPreferences;
  sms?: SmsNotificationPreferences;
  webhook?: WebhookNotificationPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Partial email preferences for create/update inputs.
 */
export interface EmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  categories?: Partial<ChannelCategoryPreferences>;
}

/**
 * Partial SMS preferences for create/update inputs.
 */
export interface SmsPreferencesInput {
  enabled?: boolean;
  categories?: Partial<ChannelCategoryPreferences>;
}

/**
 * Partial webhook preferences for create/update inputs.
 */
export interface WebhookPreferencesInput {
  enabled?: boolean;
  categories?: Partial<ChannelCategoryPreferences>;
}

/**
 * Input for creating preferences (userId required, rest optional with defaults).
 */
export interface CreatePreferencesInput {
  userId: string;
  email?: EmailPreferencesInput;
  sms?: SmsPreferencesInput;
  webhook?: WebhookPreferencesInput;
}

/**
 * Input for updating preferences (all fields optional).
 */
export interface UpdatePreferencesInput {
  email?: EmailPreferencesInput;
  sms?: SmsPreferencesInput;
  webhook?: WebhookPreferencesInput;
}

const DEFAULT_CATEGORIES: ChannelCategoryPreferences = {
  'order-confirmation': true,
  'order-status-update': true,
  'welcome': true,
  'user-updated': true,
};

/**
 * Default email notification preferences — all enabled, immediate delivery.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailNotificationPreferences = {
  enabled: true,
  frequency: 'immediate',
  categories: { ...DEFAULT_CATEGORIES },
};

/**
 * Default SMS notification preferences — all enabled.
 */
export const DEFAULT_SMS_PREFERENCES: SmsNotificationPreferences = {
  enabled: true,
  categories: { ...DEFAULT_CATEGORIES },
};

/**
 * Default webhook notification preferences — all enabled.
 */
export const DEFAULT_WEBHOOK_PREFERENCES: WebhookNotificationPreferences = {
  enabled: true,
  categories: { ...DEFAULT_CATEGORIES },
};

/**
 * Check whether a notification type is enabled for a user's email preferences.
 */
export function isEmailNotificationEnabled(
  preferences: EmailNotificationPreferences,
  notificationType: NotificationType,
): boolean {
  if (!preferences.enabled) {
    return false;
  }
  return preferences.categories[notificationType] ?? false;
}

/**
 * Check whether a notification type is enabled for a given channel's preferences.
 * Works with any channel preferences that have an enabled toggle and categories.
 */
export function isChannelNotificationEnabled(
  preferences: { enabled: boolean; categories: ChannelCategoryPreferences },
  notificationType: NotificationType,
): boolean {
  if (!preferences.enabled) {
    return false;
  }
  return preferences.categories[notificationType] ?? false;
}

/**
 * Get the effective channel preferences for a user, falling back to defaults
 * for channels not explicitly configured.
 */
export function getChannelPreferences(
  prefs: UserNotificationPreferences,
  channel: NotificationChannel,
): { enabled: boolean; categories: ChannelCategoryPreferences } {
  switch (channel) {
    case 'email':
      return prefs.email;
    case 'sms':
      return prefs.sms ?? DEFAULT_SMS_PREFERENCES;
    case 'webhook':
      return prefs.webhook ?? DEFAULT_WEBHOOK_PREFERENCES;
    default:
      // For unknown channels (e.g. 'in-app'), default to all-enabled
      return { enabled: true, categories: { ...DEFAULT_CATEGORIES } };
  }
}

