/**
 * Preferences validators — pure validation functions for preference-related inputs.
 *
 * No side effects, no database calls. Reusable across services.
 */

import type { CreatePreferencesInput, UpdatePreferencesInput, EmailFrequency } from '../models/user-preferences.js';

const VALID_FREQUENCIES: EmailFrequency[] = ['immediate', 'daily-digest', 'weekly-digest'];

/**
 * Validate input for creating user preferences.
 * Checks that userId is provided and channel settings are valid if present.
 */
export function validateCreatePreferencesInput(input: CreatePreferencesInput): void {
  if (!input.userId || input.userId.trim().length === 0) {
    throw new Error('User ID is required for preferences');
  }

  if (input.email) {
    validateEmailPreferencesInput(input.email);
  }

  if (input.sms) {
    validateChannelPreferencesInput(input.sms, 'sms');
  }

  if (input.webhook) {
    validateChannelPreferencesInput(input.webhook, 'webhook');
  }
}

/**
 * Validate input for updating user preferences.
 * Checks that channel settings are valid if present.
 */
export function validateUpdatePreferencesInput(input: UpdatePreferencesInput): void {
  if (input.email) {
    validateEmailPreferencesInput(input.email);
  }

  if (input.sms) {
    validateChannelPreferencesInput(input.sms, 'sms');
  }

  if (input.webhook) {
    validateChannelPreferencesInput(input.webhook, 'webhook');
  }
}

/**
 * Validate email preferences input fields.
 */
function validateEmailPreferencesInput(input: { frequency?: EmailFrequency }): void {
  if (input.frequency !== undefined && !VALID_FREQUENCIES.includes(input.frequency)) {
    throw new Error(`Invalid email frequency: ${input.frequency}`);
  }
}

/**
 * Validate generic channel preferences input (SMS, webhook).
 * These channels only have enabled + categories — no frequency.
 */
function validateChannelPreferencesInput(
  input: { enabled?: boolean; categories?: Record<string, boolean> },
  channelName: string,
): void {
  if (input.enabled !== undefined && typeof input.enabled !== 'boolean') {
    throw new Error(`Invalid ${channelName} enabled value: must be boolean`);
  }

  if (input.categories !== undefined) {
    for (const [key, value] of Object.entries(input.categories)) {
      if (typeof value !== 'boolean') {
        throw new Error(`Invalid ${channelName} category value for '${key}': must be boolean`);
      }
    }
  }
}

