} from '../../src/models/user-preferences.js';
import type { User } from '../../src/models/user.js';

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-0001' });

      const result = service.deletePreferences('user-0001');
      expect(result).toBe(true);

      // Should return defaults now
      const prefs = service.getPreferences('user-0001');
      expect(prefs.id).toBe('');
    });

    it('should return false if no preferences exist', () => {
      const result = service.deletePreferences('user-0001');
      expect(result).toBe(false);
    });
  });

  describe('multi-channel preferences', () => {
    it('should return default SMS and webhook preferences when none exist', () => {
      const prefs = service.getPreferences('user-0001');

      expect(prefs.sms).toBeDefined();
      expect(prefs.sms!.enabled).toBe(true);
      expect(prefs.sms!.categories['order-confirmation']).toBe(true);
      expect(prefs.webhook).toBeDefined();
      expect(prefs.webhook!.enabled).toBe(true);
      expect(prefs.webhook!.categories['order-confirmation']).toBe(true);
    });

    it('should create preferences with SMS settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        sms: {
          enabled: true,
          categories: { 'welcome': false },
        },
      });

      expect(prefs.sms).toBeDefined();
      expect(prefs.sms!.enabled).toBe(true);
      expect(prefs.sms!.categories['welcome']).toBe(false);
      expect(prefs.sms!.categories['order-confirmation']).toBe(true);
    });

    it('should create preferences with webhook settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        webhook: {
          enabled: false,
        },
      });

      expect(prefs.webhook).toBeDefined();
      expect(prefs.webhook!.enabled).toBe(false);
      expect(prefs.webhook!.categories['order-confirmation']).toBe(true);
    });

    it('should create preferences with all channels', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        email: { frequency: 'daily-digest' },
        sms: { enabled: true, categories: { 'order-status-update': false } },
        webhook: { enabled: true },
      });

      expect(prefs.email.frequency).toBe('daily-digest');
      expect(prefs.sms).toBeDefined();
      expect(prefs.sms!.categories['order-status-update']).toBe(false);
      expect(prefs.webhook).toBeDefined();
      expect(prefs.webhook!.enabled).toBe(true);
    });

    it('should update SMS preferences', () => {
      service.createPreferences({
        userId: 'user-0001',
        sms: { enabled: true },
      });

      const updated = service.updatePreferences('user-0001', {
        sms: { enabled: false },
      });

      expect(updated.sms!.enabled).toBe(false);
    });

    it('should update webhook preferences', () => {
      service.createPreferences({
        userId: 'user-0001',
        webhook: { enabled: true },
      });

      const updated = service.updatePreferences('user-0001', {
        webhook: { categories: { 'welcome': false } },
      });

      expect(updated.webhook!.enabled).toBe(true);
      expect(updated.webhook!.categories['welcome']).toBe(false);
    });

    it('should update SMS preferences using defaults when none existed', () => {
      service.createPreferences({ userId: 'user-0001' }); // email only

      const updated = service.updatePreferences('user-0001', {
        sms: { enabled: false },
      });

      expect(updated.sms!.enabled).toBe(false);
      // Categories should come from defaults
      expect(updated.sms!.categories['order-confirmation']).toBe(true);
    });

    it('should preserve email settings when updating only SMS', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { frequency: 'weekly-digest' },
      });

      const updated = service.updatePreferences('user-0001', {
        sms: { enabled: true },
      });

      expect(updated.email.frequency).toBe('weekly-digest');
      expect(updated.sms!.enabled).toBe(true);
    });
  });
});

